(window.webpackJsonp=window.webpackJsonp||[]).push([[27],{823:function(n,r,e){"use strict";e.r(r),r.default="// Author @patriciogv ( patriciogonzalezvivo.com ) - 2015\r\n// Title: Diamond Tiles\r\n\r\n#ifdef GL_ES\r\nprecision mediump float;\r\n#endif\r\n\r\n#define PI 3.14159265358979323846\r\n\r\nuniform vec2 dd_resolution;\r\nuniform float dd_time;\r\n\r\nvec2 rotate2D(vec2 _st, float _angle){\r\n    _st -= 0.5;\r\n    _st =  mat2(cos(_angle),-sin(_angle),\r\n      sin(_angle),cos(_angle)) * _st;\r\n    _st += 0.5;\r\n    return _st;\r\n}\r\n\r\nvec2 tile(vec2 _st, float _zoom){\r\n    _st *= _zoom;\r\n    return fract(_st);\r\n}\r\n\r\nfloat box(vec2 _st, vec2 _size, float _smoothEdges){\r\n    _size = vec2(0.5)-_size*0.5;\r\n    vec2 aa = vec2(_smoothEdges*0.5);\r\n    vec2 uv = smoothstep(_size,_size+aa,_st);\r\n    uv *= smoothstep(_size,_size+aa,vec2(1.0)-_st);\r\n    return uv.x*uv.y;\r\n}\r\n\r\nvec2 offset(vec2 _st, vec2 _offset){\r\n    vec2 uv;\r\n\r\n    if(_st.x>0.5){\r\n        uv.x = _st.x - 0.5;\r\n    } else {\r\n        uv.x = _st.x + 0.5;\r\n    }\r\n\r\n    if(_st.y>0.5){\r\n        uv.y = _st.y - 0.5;\r\n    } else {\r\n        uv.y = _st.y + 0.5;\r\n    }\r\n\r\n    return uv;\r\n}\r\n\r\nvoid main(void){\r\n    vec2 st = gl_FragCoord.xy/dd_resolution.xy;\r\n    st.y *= dd_resolution.y/dd_resolution.x;\r\n\r\n    st = tile(st,10.);\r\n\r\n    vec2 offsetSt = offset(st,vec2(0.5));\r\n\r\n    st = rotate2D(st,PI*0.25);\r\n\r\n    vec3 color = vec3( box(offsetSt,vec2(0.95),0.01) - box(st,vec2(0.3),0.01) + 2.*box(st,vec2(0.2),0.01) );\r\n\r\n    gl_FragColor = vec4(color,1.0);\r\n}\r\n"}}]);